import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjChart } from "./OjChart";
export { OjChart };

/**
 * Create an instance of [[OjChart]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojChart(driver, By.id('my-oj-chart'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojChart(driver: DriverLike, by: By): Promise<OjChart> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjChart
  if (!(webEl instanceof OjChart)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-chart>`);
  }
  return webEl;
}

register("oj-chart", OjChart);
